import java.util.*;

public class StringPatterns {

    // ── Minimum Window Substring ──────────────────────────────────
    // Find smallest window in s containing all chars of t
    static String minWindow(String s, String t) {
        if (s.isEmpty() || t.isEmpty()) return "";

        int[] need = new int[128]; // frequency needed
        for (char c : t.toCharArray()) need[c]++;
        int required = (int) Arrays.stream(need).filter(x -> x > 0).count();
        // number of distinct chars in t that must be in window

        int[] window = new int[128];
        int formed = 0; // distinct chars satisfied in window
        int l = 0, minLen = Integer.MAX_VALUE, minL = 0;

        for (int r = 0; r < s.length(); r++) {
            char c = s.charAt(r);
            window[c]++;
            if (need[c] > 0 && window[c] == need[c]) formed++; // just satisfied this char

            // Shrink window while all chars are satisfied
            while (formed == required) {
                if (r - l + 1 < minLen) { minLen = r - l + 1; minL = l; }
                char lc = s.charAt(l++);
                window[lc]--;
                if (need[lc] > 0 && window[lc] < need[lc]) formed--; // no longer satisfied
            }
        }
        return minLen == Integer.MAX_VALUE ? "" : s.substring(minL, minL + minLen);
    }

    // ── Find all anagram start indices in s ───────────────────────
    static List<Integer> findAnagrams(String s, String p) {
        List<Integer> result = new ArrayList<>();
        if (s.length() < p.length()) return result;

        int[] pFreq = new int[26], wFreq = new int[26];
        for (char c : p.toCharArray()) pFreq[c - 'a']++;
        for (int i = 0; i < p.length(); i++) wFreq[s.charAt(i) - 'a']++;

        if (Arrays.equals(pFreq, wFreq)) result.add(0);

        for (int r = p.length(); r < s.length(); r++) {
            wFreq[s.charAt(r) - 'a']++;              // add new char
            wFreq[s.charAt(r - p.length()) - 'a']--; // remove oldest
            if (Arrays.equals(pFreq, wFreq)) result.add(r - p.length() + 1);
        }
        return result;
    }

    public static void main(String[] args) {
        System.out.println(minWindow("ADOBECODEBANC", "ABC"));   // BANC
        System.out.println(minWindow("a", "a"));                  // a
        System.out.println(minWindow("a", "aa"));                 // (empty)

        System.out.println(findAnagrams("cbaebabacd", "abc"));   // [0, 6]
        System.out.println(findAnagrams("abab", "ab"));          // [0, 1, 2]
    }
}

import java.util.*;

public class PalindromeAndReverse {

    // ── Is palindrome (ignore non-alphanumeric) ───────────────────
    static boolean isPalindrome(String s) {
        int l = 0, r = s.length() - 1;
        while (l < r) {
            while (l < r && !Character.isLetterOrDigit(s.charAt(l))) l++;
            while (l < r && !Character.isLetterOrDigit(s.charAt(r))) r--;
            if (Character.toLowerCase(s.charAt(l)) != Character.toLowerCase(s.charAt(r)))
                return false;
            l++; r--;
        }
        return true;
    }

    // ── Longest palindromic substring (expand from center) ────────
    static String longestPalindrome(String s) {
        int start = 0, maxLen = 1;
        for (int center = 0; center < s.length(); center++) {
            // Odd length: single center
            int[] odd  = expand(s, center, center);
            // Even length: two centers
            int[] even = expand(s, center, center + 1);
            if (odd[1]  > maxLen) { maxLen = odd[1];  start = odd[0]; }
            if (even[1] > maxLen) { maxLen = even[1]; start = even[0]; }
        }
        return s.substring(start, start + maxLen);
    }

    static int[] expand(String s, int l, int r) {
        while (l >= 0 && r < s.length() && s.charAt(l) == s.charAt(r)) { l--; r++; }
        return new int[]{l + 1, r - l - 1}; // [startIdx, length]
    }

    // ── Reverse words in a sentence ───────────────────────────────
    static String reverseWords(String s) {
        String[] words = s.trim().split("\\s+"); // handle multiple spaces
        StringBuilder sb = new StringBuilder();
        for (int i = words.length - 1; i >= 0; i--) {
            sb.append(words[i]);
            if (i > 0) sb.append(' ');
        }
        return sb.toString();
    }

    // ── Is subsequence ────────────────────────────────────────────
    static boolean isSubsequence(String s, String t) {
        int si = 0;
        for (int ti = 0; ti < t.length() && si < s.length(); ti++)
            if (t.charAt(ti) == s.charAt(si)) si++;
        return si == s.length();
    }

    public static void main(String[] args) {
        System.out.println(isPalindrome("A man, a plan, a canal: Panama")); // true
        System.out.println(isPalindrome("race a car"));                      // false
        System.out.println(longestPalindrome("babad"));  // bab or aba
        System.out.println(longestPalindrome("cbbd"));   // bb
        System.out.println(reverseWords("  hello world  ")); // world hello
        System.out.println(isSubsequence("ace", "abcde")); // true
        System.out.println(isSubsequence("aec", "abcde")); // false
    }
}

